**Global save tracking:**
```typescript
// In a global store or context
export const useSaveStatus = create((set) => ({
  status: 'idle',
  lastSaveTime: null,

  setSaving: () => set({ status: 'saving' }),
  setSaved: () => set({ status: 'saved', lastSaveTime: new Date() }),
