### Fix 4: Single File Overwrite + Hidden Versioning (Sprint 3)

**User-facing behavior:**
- Folder shows: `Neuman.Brain` (one file, always overwritten)
- Hidden folder: `.neuman-backups/` (last 7 versions)

**Implementation:**
```typescript
export const autoSaveWithSmartRotation = async (
  directoryHandle: FileSystemDirectoryHandle
): Promise<ExportResult> => {
  // 1. Create main file (always overwrite)
  const mainFile = await directoryHandle.getFileHandle('Neuman.Brain', { create: true });
  const writable = await mainFile.createWritable();
  await writable.write(brainData);
  await writable.close();

  // 2. Create hidden version in .neuman-backups/
  const backupDir = await directoryHandle.getDirectoryHandle('.neuman-backups', { create: true });
  const timestamp = new Date().toISOString().replace(/:/g, '-').split('.')[0];
  const versionFile = await backupDir.getFileHandle(`backup-${timestamp}.brain`, { create: true });
  const versionWritable = await versionFile.createWritable();
  await versionWritable.write(brainData);
  await versionWritable.close();

  // 3. Delete old versions (keep last 7)
  const versions = await listBackupsInDirectory(backupDir);
  if (versions.length > 7) {
    const toDelete = versions.slice(7);
    for (const old of toDelete) {
      await backupDir.removeEntry(old.name);
    }
  }

  return { filename: 'Neuman.Brain', size: brainData.size };
};
```

**Why:** Clean folder + safety net

