### Fix 5: Directory Handle Persistence (Sprint 3)

**Add to brainBackup.ts:**
```typescript
export const saveDirectoryHandle = async (
  handle: FileSystemDirectoryHandle
): Promise<void> => {
  await indexedDBService.setItem('auto-save-directory-handle', handle);
};

export const getDirectoryHandle = async (): Promise<FileSystemDirectoryHandle | null> => {
  try {
    const handle = await indexedDBService.getItem('auto-save-directory-handle');
    if (!handle) return null;

    // Verify permission
    const permission = await (handle as FileSystemDirectoryHandle).queryPermission({ mode: 'readwrite' });
    if (permission === 'granted') {
      return handle as FileSystemDirectoryHandle;
    }

    // Request permission again
    const newPermission = await (handle as FileSystemDirectoryHandle).requestPermission({ mode: 'readwrite' });
    if (newPermission === 'granted') {
      return handle as FileSystemDirectoryHandle;
    }
  } catch (error) {
    console.error('Failed to restore directory handle:', error);
  }
  return null;
};
```

**Update autoSave.ts initialize():**
```typescript
async initialize(): Promise<void> {
  // Restore directory from IndexedDB
  const savedHandle = await getDirectoryHandle();
  if (savedHandle) {
    this.localDirectory = savedHandle;
    console.log('✅ Restored directory handle');
  }

  if (this.localDirectory) {
    this.isEnabled = true;
    this.startWatching();
  }
}
```

**Why:** No more re-picking folder!

